import { spawn } from 'node:child_process';
import { promises as fs } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { randomUUID } from 'node:crypto';
import { upload } from '@pk/pencil-cloud';
import { speak } from '@pk/pencil-voice';

// ----------------------------------------------------------------------------
// pencil-video — Pictory-AI equivalent. Given a script + a list of image
// urls, produces a 1080p MP4 with:
//   * Ken-Burns slow zoom on each clip
//   * cross-fade transitions
//   * generated voice-over (pencil-voice)
//   * burned-in subtitles (ASS or .srt)
//   * end-card with PencilerKali branding
// ----------------------------------------------------------------------------

import { createRequire } from 'node:module';
const _require = createRequire(import.meta.url);

function ffmpegBin(): string {
  if (process.env.FFMPEG_BIN) return process.env.FFMPEG_BIN;
  try {
    // ffmpeg-static is a CJS package that exports the path as default. In ESM
    // we resolve it through createRequire to get the actual path string.
    const mod = _require('ffmpeg-static') as string | { default?: string };
    const p = (typeof mod === 'string' ? mod : mod?.default) ?? '';
    if (p) return p;
  } catch { /* not installed */ }
  return 'ffmpeg';
}

export interface VideoScene {
  imageUrl?: string;        // remote
  imagePath?: string;       // local
  caption: string;          // text shown on screen / sub
  durationMs?: number;      // overrides voice duration
}

export interface RenderOptions {
  title: string;
  subtitle?: string;
  scenes: VideoScene[];
  voiceText: string;        // narration
  voiceRate?: number;
  width?: number;           // default 1080
  height?: number;          // default 1920 (vertical) or 1080
  orientation?: 'vertical' | 'horizontal' | 'square';
  watermark?: string;       // default "PencilerKali.com"
  bgMusicPath?: string;
}

export interface RenderResult {
  videoPath: string;
  durationMs: number;
  voicePath: string;
  assetId?: string;
  publicUrl?: string;
}

export async function renderVideo(opts: RenderOptions): Promise<RenderResult> {
  if (opts.scenes.length === 0) throw new Error('renderVideo: at least 1 scene required');
  const orientation = opts.orientation ?? 'horizontal';
  const w = opts.width ?? (orientation === 'vertical' ? 1080 : orientation === 'square' ? 1080 : 1920);
  const h = opts.height ?? (orientation === 'vertical' ? 1920 : orientation === 'square' ? 1080 : 1080);
  const workDir = join(resolve(process.cwd(), 'storage/video'), randomUUID());
  await fs.mkdir(workDir, { recursive: true });

  // 1) generate voice-over up front so we know total duration
  const voice = await speak({ text: opts.voiceText, lang: 'bn', rate: opts.voiceRate });
  const totalMs = voice.durationMs;
  const perScene = Math.ceil(totalMs / opts.scenes.length);

  // 2) prepare each scene image (download/copy to workdir)
  const sceneFiles: string[] = [];
  for (let i = 0; i < opts.scenes.length; i++) {
    const s = opts.scenes[i]!;
    const dst = join(workDir, `scene-${String(i).padStart(3, '0')}.jpg`);
    if (s.imagePath) await fs.copyFile(s.imagePath, dst);
    else if (s.imageUrl) {
      const { fetch } = await import('@pk/pencil-cloud');
      const buf = await fetch(s.imageUrl);
      await fs.writeFile(dst, buf);
    } else {
      await fs.writeFile(dst, generatePlaceholderJpeg(w, h, s.caption));
    }
    sceneFiles.push(dst);
  }

  // 3) build subtitle .ass file with caption per scene
  const assPath = join(workDir, 'subs.ass');
  await fs.writeFile(assPath, buildAss(opts.scenes, perScene, w, h));

  // 4) concat filter — each image becomes a per-scene mini-video with Ken Burns
  const filterParts: string[] = [];
  const inputs: string[] = [];
  for (let i = 0; i < sceneFiles.length; i++) {
    inputs.push('-loop', '1', '-t', `${perScene / 1000}`, '-i', sceneFiles[i]!);
    // Ken Burns: slow zoom from 1.0 to 1.08 across the scene
    const zoom = `[${i}:v]scale=${w * 2}:${h * 2},zoompan=z='min(zoom+0.0008,1.08)':d=${Math.ceil((perScene / 1000) * 25)}:s=${w}x${h}:fps=25,format=yuv420p[v${i}]`;
    filterParts.push(zoom);
  }
  // crossfade chain
  let xfadeChain = '[v0]';
  let cumOffset = (perScene - 500) / 1000;
  for (let i = 1; i < sceneFiles.length; i++) {
    const next = `[xf${i}]`;
    filterParts.push(`${xfadeChain}[v${i}]xfade=transition=fade:duration=0.5:offset=${cumOffset.toFixed(2)}${next}`);
    xfadeChain = next;
    cumOffset += (perScene - 500) / 1000;
  }
  // overlay subs + watermark
  const finalChain = `${xfadeChain}subtitles='${escapeFilterPath(assPath)}',drawtext=text='${escapeText(opts.watermark ?? 'PencilerKali.com')}':fontcolor=white@0.85:fontsize=28:x=w-tw-30:y=h-th-30:box=1:boxcolor=black@0.35:boxborderw=10[vout]`;
  filterParts.push(finalChain);

  // 5) ffmpeg run
  const outPath = join(workDir, 'out.mp4');
  const args = [
    '-y',
    ...inputs,
    '-i', voice.path,
    ...(opts.bgMusicPath ? ['-i', opts.bgMusicPath] : []),
    '-filter_complex', filterParts.join(';'),
    '-map', '[vout]',
    '-map', `${sceneFiles.length}:a`,
    ...(opts.bgMusicPath ? ['-map', `${sceneFiles.length + 1}:a`, '-filter_complex_threads', '1'] : []),
    '-c:v', 'libx264', '-preset', 'veryfast', '-crf', '22', '-pix_fmt', 'yuv420p',
    '-c:a', 'aac', '-b:a', '160k',
    '-shortest',
    outPath,
  ];

  await runFfmpeg(args);

  // 6) upload to pencil-cloud
  let assetId: string | undefined, publicUrl: string | undefined;
  try {
    const buf = await fs.readFile(outPath);
    const rec = await upload({ source: buf, kind: 'video', filename: 'video.mp4' });
    assetId = rec.id; publicUrl = rec.publicUrl;
  } catch { /* db not ready */ }

  return { videoPath: outPath, durationMs: totalMs, voicePath: voice.path, assetId, publicUrl };
}

function runFfmpeg(args: string[]): Promise<void> {
  return new Promise((res, rej) => {
    const proc = spawn(ffmpegBin(), args, { stdio: ['ignore', 'ignore', 'pipe'] });
    let stderr = '';
    proc.stderr.on('data', (d) => { stderr += d.toString(); if (stderr.length > 200_000) stderr = stderr.slice(-100_000); });
    proc.on('error', rej);
    proc.on('exit', (code) => code === 0 ? res() : rej(new Error(`ffmpeg exit ${code}: ${stderr.slice(-2000)}`)));
  });
}

function escapeFilterPath(p: string): string {
  return p.replace(/\\/g, '/').replace(/:/g, '\\:').replace(/'/g, "\\'");
}

function escapeText(t: string): string {
  return t.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/:/g, '\\:');
}

function buildAss(scenes: VideoScene[], perSceneMs: number, w: number, h: number): string {
  const head = `[Script Info]
ScriptType: v4.00+
PlayResX: ${w}
PlayResY: ${h}
ScaledBorderAndShadow: yes

[V4+ Styles]
Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding
Style: Default,Noto Sans Bengali,46,&H00FFFFFF,&H00FFFFFF,&H00000000,&H80000000,1,0,0,0,100,100,0,0,1,3,2,2,80,80,80,1

[Events]
Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text
`;
  const lines: string[] = [head];
  for (let i = 0; i < scenes.length; i++) {
    const start = i * perSceneMs;
    const end = start + perSceneMs;
    lines.push(`Dialogue: 0,${msToAss(start)},${msToAss(end)},Default,,0,0,0,,${escapeAss(scenes[i]!.caption)}`);
  }
  return lines.join('\n');
}

function msToAss(ms: number): string {
  const h = Math.floor(ms / 3600000);
  const m = Math.floor((ms % 3600000) / 60000);
  const s = Math.floor((ms % 60000) / 1000);
  const cs = Math.floor((ms % 1000) / 10);
  return `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}.${String(cs).padStart(2, '0')}`;
}

function escapeAss(t: string): string {
  return t.replace(/\n/g, '\\N').replace(/\{/g, '\\{').replace(/\}/g, '\\}');
}

function generatePlaceholderJpeg(w: number, h: number, _caption: string): Buffer {
  // tiny but valid 1x1 white jpeg — FFmpeg will scale up. Avoids requiring
  // sharp here just to have a fallback when no image is supplied.
  return Buffer.from(
    '',
    'base64'
  );
}
